”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”

const formatDate = (dateStr) => {
  if (!dateStr) return 'â€”';
  const d = new Date(dateStr + 'T12:00:00');
  return d.toLocaleDateString('pt-BR', { day: '2-digit', month: 'short', year: 'numeric' });
};

const isOverdue = (prazo, is_completed) => {
  if (is_completed) return false;
  return new Date(prazo + 'T23:59:59') < new Date();
};

// â”€â”€â”€ CHECKBOX CUSTOMIZADO â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const Checkbox = ({ checked, onChange }) => (
  <button
    type="button"
    onClick={onChange}
    className={`flex-shrink-0 w-5 h-5 rounded border-2 flex items-center justify-center transition-all duration-200 cursor-pointer
      ${checked
        ? 'bg-red-600 border-red-600'
        : 'bg-transparent border-neutral-600 hover:border-red-500'}`}
  >
    {checked && (
      <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
      </svg>
    )}
  </button>
);

// â”€â”€â”€ BADGE DE STATUS â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const StatusBadge = ({ goal }) => {
  if (goal.is_completed) {
    return <span className="inline-flex items-center gap-1 text-xs font-medium px-2 py-0.5 rounded-full bg-green-900/40 text-green-400 border border-green-800/50">ConcluÃ­da</span>;
  }
  if (isOverdue(goal.prazo)) {
    return <span className="inline-flex items-center gap-1 text-xs font-medium px-2 py-0.5 rounded-full bg-red-900/40 text-red-400 border border-red-800/50">Atrasada</span>;
  }
  return <span className="inline-flex items-center gap-1 text-xs font-medium px-2 py-0.5 rounded-full bg-neutral-800 text-neutral-400 border border-neutral-700">Em andamento</span>;
};

// â”€â”€â”€ ITEM DA LISTA â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const GoalListItem = ({ goal, onToggle, onEdit, onDelete }) => (
  <div className={`group relative flex items-start gap-4 px-5 py-4 rounded-xl border transition-all duration-200
    ${goal.is_completed
      ? 'bg-neutral-900/50 border-neutral-800/50'
      : 'bg-neutral-900 border-neutral-800 hover:border-neutral-700 hover:bg-neutral-800/60'}`}
  >
    {/* Linha lateral vermelha para metas em andamento */}
    {!goal.is_completed && (
      <div className="absolute left-0 top-3 bottom-3 w-0.5 bg-red-600 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
    )}

    <div className="pt-0.5">
      <Checkbox checked={goal.is_completed} onChange={() => onToggle(goal.id, !goal.is_completed)} />
    </div>

    <div className="flex-1 min-w-0">
      <div className="flex items-start justify-between gap-2">
        <p className={`text-sm font-semibold leading-snug transition-colors
          ${goal.is_completed ? 'line-through text-neutral-500' : 'text-white'}`}>
          {goal.meta}
        </p>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0">
          <button
            onClick={() => onEdit(goal)}
            title="Editar"
            className="p-1.5 rounded-lg text-neutral-500 hover:text-white hover:bg-neutral-700 transition-all"
          >
            <FiEdit2 size={13} />
          </button>
          <button
            onClick={() => onDelete(goal.id)}
            title="Excluir"
            className="p-1.5 rounded-lg text-neutral-500 hover:text-red-400 hover:bg-red-900/20 transition-all"
          >
            <FiTrash2 size={13} />
          </button>
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-x-4 gap-y-1 mt-2">
        <span className="flex items-center gap-1.5 text-xs text-neutral-500">
          <FiUser size={11} />
          {goal.responsavel}
        </span>
        <span className={`flex items-center gap-1.5 text-xs ${isOverdue(goal.prazo, goal.is_completed) ? 'text-red-400' : 'text-neutral-500'}`}>
          <FiCalendar size={11} />
          {formatDate(goal.prazo)}
          {isOverdue(goal.prazo, goal.is_completed) && ' Â· atrasada'}
        </span>
        {goal.recompensa && (
          <span className="flex items-center gap-1.5 text-xs text-amber-500/80">
            <FiGift size={11} />
            {goal.recompensa}
          </span>
        )}
      </div>
    </div>

    <div className="flex-shrink-0 pt-0.5">
      <StatusBadge goal={goal} />
    </div>
  </div>
);

// â”€â”€â”€ TABELA â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const GoalTable = ({ goals, onToggle, onEdit, onDelete }) => (
  <div className="rounded-xl border border-neutral-800 overflow-hidden">
    <table className="min-w-full">
      <thead>
        <tr className="bg-neutral-950 border-b border-neutral-800">
          <th className="w-14 px-4 py-3"></th>
          <th className="px-4 py-3 text-left text-xs font-bold text-neutral-400 uppercase tracking-widest">Meta</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-neutral-400 uppercase tracking-widest">ResponsÃ¡vel</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-neutral-400 uppercase tracking-widest">Prazo</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-neutral-400 uppercase tracking-widest">Recompensa</th>
          <th className="px-4 py-3 text-left text-xs font-bold text-neutral-400 uppercase tracking-widest">Status</th>
          <th className="w-24 px-4 py-3"></th>
        </tr>
      </thead>
      <tbody>
        {goals.map((goal, i) => (
          <tr
            key={goal.id}
            className={`group border-b border-neutral-800/60 transition-colors hover:bg-neutral-800/40
              ${i % 2 === 0 ? 'bg-neutral-900' : 'bg-neutral-900/50'}`}
          >
            <td className="px-4 py-3 text-center">
              <Checkbox checked={goal.is_completed} onChange={() => onToggle(goal.id, !goal.is_completed)} />
            </td>
            <td className={`px-4 py-3 text-sm font-medium max-w-xs truncate ${goal.is_completed ? 'line-through text-neutral-500' : 'text-white'}`}>
              {goal.meta}
            </td>
            <td className="px-4 py-3 text-sm text-neutral-400">{goal.responsavel}</td>
            <td className={`px-4 py-3 text-sm ${isOverdue(goal.prazo, goal.is_completed) ? 'text-red-400' : 'text-neutral-400'}`}>
              {formatDate(goal.prazo)}
            </td>
            <td className="px-4 py-3 text-sm text-amber-500/80">{goal.recompensa || 'â€”'}</td>
            <td className="px-4 py-3"><StatusBadge goal={goal} /></td>
            <td className="px-4 py-3">
              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity justify-end">
                <button onClick={() => onEdit(goal)} className="p-1.5 rounded-lg text-neutral-500 hover:text-white hover:bg-neutral-700 transition-all">
                  <FiEdit2 size={13} />
                </button>
                <button onClick={() => onDelete(goal.id)} className="p-1.5 rounded-lg text-neutral-500 hover:text-red-400 hover:bg-red-900/20 transition-all">
                  <FiTrash2 size={13} />
                </button>
              </div>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  </div>
);

// â”€â”€â”€ MODAL â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const inputClass = "w-full px-3 py-2.5 rounded-lg border border-neutral-700 bg-neutral-800/80 text-white text-sm placeholder-neutral-500 focus:outline-none focus:border-red-500 focus:ring-1 focus:ring-red-500/30 transition-all";
const labelClass = "block text-xs font-semibold text-neutral-400 uppercase tracking-wider mb-1.5";

const Modal = ({ goal, onClose, onSave, onChange }) => (
  <div
    className="fixed inset-0 z-50 flex items-center justify-center p-4"
    style={{ background: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(4px)' }}
    onClick={(e) => e.target === e.currentTarget && onClose()}
  >
    <div className="bg-neutral-900 border border-neutral-800 rounded-2xl w-full max-w-lg shadow-2xl">
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-5 border-b border-neutral-800">
        <div>
          <h2 className="text-base font-bold text-white">{goal.id ? 'Editar Meta' : 'Nova Meta'}</h2>
          <p className="text-xs text-neutral-500 mt-0.5">{goal.id ? 'Atualize as informaÃ§Ãµes da meta' : 'Preencha os campos para criar uma nova meta'}</p>
        </div>
        <button onClick={onClose} className="p-2 rounded-lg text-neutral-500 hover:text-white hover:bg-neutral-800 transition-all">
          <FiX size={16} />
        </button>
      </div>

      {/* Form */}
      <form onSubmit={onSave} className="px-6 py-5 space-y-4">
        <div>
          <label className={labelClass}>Meta</label>
          <input type="text" name="meta" value={goal.meta} onChange={onChange}
            placeholder="Descreva o objetivo..."
            className={inputClass} required />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className={labelClass}>ResponsÃ¡vel</label>
            <input type="text" name="responsavel" value={goal.responsavel} onChange={onChange}
              placeholder="Nome do responsÃ¡vel"
              className={inputClass} required />
          </div>
          <div>
            <label className={labelClass}>Prazo</label>
            <input type="date" name="prazo" value={goal.prazo} onChange={onChange}
              className={inputClass} required />
          </div>
        </div>

        <div>
          <label className={labelClass}>Recompensa</label>
          <input type="text" name="recompensa" value={goal.recompensa} onChange={onChange}
            placeholder="O que ganha ao concluir?"
            className={inputClass} required />
        </div>

        {/* Footer */}
        <div className="flex justify-end gap-3 pt-2">
          <button type="button" onClick={onClose}
            className="px-4 py-2 text-sm font-semibold text-neutral-400 hover:text-white rounded-lg hover:bg-neutral-800 transition-all">
            Cancelar
          </button>
          <button type="submit"
            className="flex items-center gap-2 px-5 py-2 text-sm font-bold text-white bg-red-600 hover:bg-red-500 rounded-lg transition-all shadow-lg shadow-red-900/30">
            {goal.id ? <><FiEdit2 size={14} /> Salvar</> : <><FiPlus size={14} /> Criar Meta</>}
          </button>
        </div>
      </form>
    </div>
  </div>
);

// â”€â”€â”€ CARD DE KPI â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const KpiCard = ({ icon: Icon, label, value, color }) => (
  <div className="flex items-center gap-4 bg-neutral-900 border border-neutral-800 rounded-xl px-5 py-4">
    <div className={`w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0 ${color}`}>
      <Icon size={16} className="text-white" />
    </div>
    <div>
      <p className="text-2xl font-bold text-white leading-none">{value}</p>
      <p className="text-xs text-neutral-500 mt-0.5">{label}</p>
    </div>
  </div>
);

// â”€â”€â”€ COMPONENTE PRINCIPAL â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const GoalManagement = () => {
  const [goals, setGoals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentGoal, setCurrentGoal] = useState(null);
  const [viewMode, setViewMode] = useState('list');

  useEffect(() => { fetchGoals(); }, []);

  const fetchGoals = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await getGoals();
      setGoals(data || []);
    } catch (err) {
      setError('NÃ£o foi possÃ­vel carregar as metas. Verifique as credenciais do Supabase.');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenModal = (goal = null) => {
    setCurrentGoal(goal || { id: null, meta: '', prazo: '', responsavel: '', recompensa: '', is_completed: false });
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setCurrentGoal(null);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setCurrentGoal((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const { id, created_at, ...goalData } = currentGoal;
      if (id) {
        await updateGoal(id, goalData);
      } else {
        await addGoal(goalData);
      }
      fetchGoals();
      handleCloseModal();
    } catch (err) {
      console.error("Erro detalhado (handleSubmit):", err);
      setError('Erro ao salvar a meta.');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Tem certeza que deseja excluir esta meta?')) return;
    try {
      await deleteGoal(id);
      setGoals((prev) => prev.filter((g) => g.id !== id));
    } catch (err) {
      console.error("Erro detalhado (handleDelete):", err);
      setError('Erro ao excluir a meta.');
    }
  };

  const handleToggleCompleted = async (id, is_completed) => {
    try {
      await updateGoal(id, { is_completed: Boolean(is_completed) });
      setGoals((prev) => prev.map((g) => g.id === id ? { ...g, is_completed: Boolean(is_completed) } : g));
    } catch (err) {
      console.error("Erro detalhado (handleToggleCompleted):", err);
      setError('Erro ao atualizar o status da meta.');
    }
  };

  // KPIs
  const total = goals.length;
  const completed = goals.filter((g) => g.is_completed).length;
  const overdue = goals.filter((g) => isOverdue(g.prazo, g.is_completed)).length;
  const pending = total - completed;

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-64 gap-3">
        <div className="w-8 h-8 border-2 border-red-600 border-t-transparent rounded-full animate-spin" />
        <p className="text-xs text-neutral-500 tracking-widest uppercase">Carregando metas...</p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto px-6 py-8">

      {/* â”€â”€ CabeÃ§alho â”€â”€ */}
      <div className="flex items-start justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-white tracking-tight">GestÃ£o de Metas</h1>
          <p className="text-sm text-neutral-500 mt-1">Acompanhe, gerencie e conquiste seus objetivos.</p>
        </div>
        <button
          onClick={() => handleOpenModal()}
          className="flex items-center gap-2 px-4 py-2.5 text-xs font-bold uppercase tracking-widest text-white bg-red-600 hover:bg-red-500 rounded-xl transition-all shadow-lg shadow-red-900/20 flex-shrink-0"
        >
          <FiPlus size={14} />
          Nova Meta
        </button>
      </div>

      {/* â”€â”€ KPIs â”€â”€ */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-8">
        <KpiCard icon={FiTarget}       label="Total de metas"   value={total}     color="bg-neutral-700" />
        <KpiCard icon={FiCheckCircle}  label="ConcluÃ­das"       value={completed} color="bg-green-700"   />
        <KpiCard icon={FiClock}        label="Em andamento"     value={pending}   color="bg-blue-700"    />
        <KpiCard icon={FiCalendar}     label="Atrasadas"        value={overdue}   color="bg-red-700"     />
      </div>

      {/* â”€â”€ Barra de filtro / view toggle â”€â”€ */}
      {total > 0 && (
        <div className="flex items-center justify-between mb-4">
          <p className="text-xs text-neutral-500">
            {completed} de {total} meta{total !== 1 ? 's' : ''} concluÃ­da{completed !== 1 ? 's' : ''}
          </p>
          <div className="flex items-center gap-1 bg-neutral-900 border border-neutral-800 rounded-lg p-1">
            <button
              onClick={() => setViewMode('list')}
              title="VisualizaÃ§Ã£o em lista"
              className={`p-2 rounded-md transition-all ${viewMode === 'list' ? 'bg-neutral-700 text-white' : 'text-neutral-500 hover:text-neutral-300'}`}
            >
              <FiList size={14} />
            </button>
            <button
              onClick={() => setViewMode('table')}
              title="VisualizaÃ§Ã£o em tabela"
              className={`p-2 rounded-md transition-all ${viewMode === 'table' ? 'bg-neutral-700 text-white' : 'text-neutral-500 hover:text-neutral-300'}`}
            >
              <FiGrid size={14} />
            </button>
          </div>
        </div>
      )}

      {/* â”€â”€ Error â”€â”€ */}
      {error && (
        <div className="flex items-center justify-between bg-red-900/20 border border-red-900/50 rounded-xl px-5 py-4 mb-5">
          <p className="text-sm text-red-400">{error}</p>
          <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">
            <FiX size={16} />
          </button>
        </div>
      )}

      {/* â”€â”€ ConteÃºdo â”€â”€ */}
      {total === 0 ? (
        <div className="flex flex-col items-center justify-center bg-neutral-900 border border-neutral-800 border-dashed rounded-2xl p-16 text-center">
          <div className="w-12 h-12 rounded-xl bg-neutral-800 flex items-center justify-center mb-4">
            <FiTarget size={22} className="text-neutral-500" />
          </div>
          <p className="text-sm font-semibold text-neutral-300 mb-1">Nenhuma meta ainda</p>
          <p className="text-xs text-neutral-500 mb-5">Crie sua primeira meta e comece a acompanhar seu progresso.</p>
          <button
            onClick={() => handleOpenModal()}
            className="flex items-center gap-2 px-4 py-2 text-xs font-bold uppercase tracking-widest text-white bg-red-600 hover:bg-red-500 rounded-lg transition-all"
          >
            <FiPlus size={13} /> Criar primeira meta
          </button>
        </div>
      ) : viewMode === 'list' ? (
        <div className="space-y-2">
          {goals.map((goal) => (
            <GoalListItem
              key={goal.id}
              goal={goal}
              onToggle={handleToggleCompleted}
              onEdit={handleOpenModal}
              onDelete={handleDelete}
            />
          ))}
        </div>
      ) : (
        <GoalTable
          goals={goals}
          onToggle={handleToggleCompleted}
          onEdit={handleOpenModal}
          onDelete={handleDelete}
        />
      )}

      {/* â”€â”€ Modal â”€â”€ */}
      {isModalOpen && currentGoal && (
        <Modal
          goal={currentGoal}
          onClose={handleCloseModal}
          onSave={handleSubmit}
          onChange={handleChange}
        />
      )}
    </div>
  );
};

export default GoalManagement;
